// T064: Query n8n API for today's LinkedIn action executions
// Uses N8N_API_KEY environment variable (already in container)
// Counts successful executions of linkedin-post, linkedin-comment, linkedin-like
// Flags alert if >= 120 (80% of 150 daily limit)

// 019: Read API key from Static Data (not $env)
const staticData = $getWorkflowStaticData('global');
const hookToken = staticData.hookToken || '';
const apiKey = staticData.n8nApiKey;
if (!apiKey) {
  return [{ json: { status: 'error', error: 'N8N_API_KEY not set in environment' } }];
}

const today = new Date();
today.setHours(0, 0, 0, 0);
const startOfDay = today.toISOString();

const workflowNames = ['linkedin-post', 'linkedin-comment', 'linkedin-like'];
let totalSuccessful = 0;
const breakdown = {};

for (const wfName of workflowNames) {
  try {
    const response = await fetch(
      `http://localhost:5678/api/v1/executions?status=success&workflowId=${wfName}&startedAfter=${encodeURIComponent(startOfDay)}&limit=200`,
      {
        headers: {
          'X-N8N-API-KEY': apiKey
        }
      }
    );

    if (response.ok) {
      const data = await response.json();
      const count = data.data ? data.data.length : 0;
      breakdown[wfName] = count;
      totalSuccessful += count;
    } else {
      breakdown[wfName] = 0;
    }
  } catch (e) {
    // API may not be reachable in stub/test mode
    breakdown[wfName] = 0;
  }
}

const dailyLimit = 150;
const alertThreshold = 120; // 80% of daily limit
const alertNeeded = totalSuccessful >= alertThreshold;

return [{
  json: {
    status: alertNeeded ? 'threshold_exceeded' : 'ok',
    total_actions_today: totalSuccessful,
    daily_limit: dailyLimit,
    alert_threshold: alertThreshold,
    alert_needed: alertNeeded,
    hookToken,
    utilization_pct: Math.round((totalSuccessful / dailyLimit) * 100),
    breakdown: breakdown,
    checked_at: new Date().toISOString()
  }
}];
